import sys
from functools import wraps

def bracket(function):
    @wraps(function)
    def wrapper(value):
        # TODO: decorate the transformed return value at call time
        return function(value).upper()
    return wrapper

@bracket
def label(value):
    return value

print(label(sys.stdin.read().strip()))

