def reverse_letters(text):
    for letter in reversed(text):
        yield letter

print(*reverse_letters("abc"))

from dataclasses import dataclass

@dataclass
class Point:
    x: int
    y: int

    def total(self):
        return self.x + self.y

point = Point(4, 5)
print(f"{point.total()}:{point == Point(4, 5)}")

from typing import Iterable, get_type_hints

def head(words: Iterable[str]) -> str:
    return next(iter(words), "missing")

hints = get_type_hints(head)
print(hints["return"].__name__, head(["elm", "oak"]))
